module RefModule(in,ld,clk,rst,q);input ld,clk,rst;
  input [3:0] in;
  output q;
  reg [3:0]qq;
  wire __q_tmp = qq[0];
  assign q = __q_tmp;
  always @ (posedge clk, posedge rst)
    begin
      if(rst)
         qq<=0; 
      else if(ld)
          qq <=in;
      else
        qq <= {1'b0,qq[3:1]};
    end
endmodule
